<template>
  <div class="my-popups">
    <div class="modal d-block">
      <div class="modal-dialog modal-dialog-centered">
        <div class="modal-content">
          <div class="modal-header theme-primary partition-full d-flex">
            <h4 class="modal-title">{{ $t(NewTabName) }} {{ $t("CheckList") }}</h4>
            <button type="button" class="close" @click="CloseTemplate">
              <em class="fa fa-times" aria-hidden="true"></em>
            </button>
          </div>

          <!-- ✅ Search -->




          <div class="col-12 py-3">
            <div class="row">
              <div class="col-md-4">
                <input class="form-control" type="text" v-model="SearchName" placeholder="Search by Name"
                  @input="SearchChecklistName" />
              </div>
              <div class="col-md-4">
                <a @click="SearchChecklistName" href="javascript:;" class="btn btn-success px-4 mr-2">
                  <i class="fa fa-search"></i>
                </a>
                <a @click="RefreshSearchTemplate" href="javascript:;" class="btn btn-danger px-4">
                  <i class="fa fa-refresh"></i>
                </a>
              </div>

              <div class="col-md-4">
                <a href="javascript:;" class="btn btn-primary float-right" @click="AddCheckList"><i
                    class="fa fa-plus pr-2"></i>{{ $t('AddChecklist') }}</a>
              </div>


            </div>
          </div>

          <!-- ✅ Table -->
          <div class="col-12 pt-2">
            <div class="listing">
              <div class="table-responsive table-fix-header" style="max-height:530px;">
                <table class="table table-bordered mt-0">
                  <thead class="thead-bg">
                    <tr>
                      <th style="width:50px;" class="text-center">
                        <div class="custom-control custom-checkbox">
                          <input type="checkbox" class="custom-control-input" id="chkAll" v-model="selectAll"
                            @change="toggleSelectAll" />
                          <label class="custom-control-label" for="chkAll"></label>
                        </div>
                      </th>
                      <th>{{ $t("ChecklistName") }}</th>
                      <th>{{ $t("MODULE_NAME") }}</th>
                      <th>{{ $t("StatusName") }}</th>
                      <th>{{ $t("Action") }}</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr v-for="item in CheckListdata" :key="item.checklist_id">
                      <td class="text-center">
                        <div class="custom-control custom-checkbox">
                          <input type="checkbox" class="custom-control-input" :id="'checkbox_' + item.checklist_id"
                            :value="item.checklist_id" v-model="selectedIds" />
                          <label class="custom-control-label" :for="'checkbox_' + item.checklist_id"></label>
                        </div>
                      </td>
                      <td>{{ item.checklist_name }}</td>
                      <td>{{ item.module_name }}</td>
                      <td>
                        <span class="text-center text-white d-block" :style="{ backgroundColor: item.status_bg_color }">
                          {{ item.status_name }}
                        </span>
                      </td>

                      <td class="text-center single-action only-for-action-col">                      
                        <a typetitle="Edit" typefor="Edit" title="Edit" class="actions-onclick" @click="EditCheckList(item)"><em
                            class="fa fa-pencil action-icon "></em></a>
                        <a typetitle="Delete" typefor="Delete" title="Delete" class="actions-onclick" @click="commonDeleteData(item.checklist_id)"><em
                            class="fa fa-trash-o action-icon text-danger"></em></a>
                      </td>
                    </tr>
                    <tr v-if="CheckListdata.length === 0">
                      <td colspan="4" class="text-center text-danger">
                        {{ $t('NoRecordfound') }}
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>

          </div>

          <!-- ✅ Footer Buttons -->
          <div class="row flex-row-reverse p-3">
            <div class="col-lg-6 text-right">
              <a href="javascript:;" class="btn btn-success mr-2" @click="SaveChecklistdata">
                <i class="fa fa-save pr-2"></i>{{ $t("Save") }}
              </a>
              <a href="javascript:;" class="btn btn-danger" @click="CloseTemplate">
                <i class="fa fa-close pr-2"></i>{{ $t("Cancel") }}
              </a>
            </div>
          </div>


        </div>
      </div>
    </div>
    <AddCheckList v-if="IsAddCheckList" :IndustryType_Id="IndustryType_Id" :CheckListId="CheckListId" @CloseCheckList="CloseCheckList">
    </AddCheckList>
  </div>
</template>

<script>
import DataService from '../../services/DataService';
import AddCheckList from './AddCheckList.vue';

export default {
  components: { AddCheckList },
  props: {
    TaskId: { type: Number, required: true }, NewTabName: { type: String }, IndustryType_Id: { type: Number, required: true }
  },
  data() {
    return {
      CheckListdata: [],
      selectedIds: [], // ✅ reactive list of selected checklists
      SearchName: '',
      selectAll: false,
      tabdispalyname: '',
      IsAddCheckList: false,
      CheckListId:0,
      userId:null,
      companyId:null
    };
  },
  watch: {
    // ✅ Automatically update selectAll state when individual items change
    selectedIds() {
      this.selectAll = this.selectedIds.length === this.CheckListdata.length;
    }
  },
  created() {
    this.userId = this.GetUserInfo.ID;
    this.companyId = this.GetUserInfo.CompanyId;
    this.CheckListDeatails();    
  },
  methods: {
    toggleSelectAll() {
      if (this.selectAll) {
        this.selectedIds = this.CheckListdata.map(i => i.checklist_id);
      } else {
        this.selectedIds = [];
      }
    },
    CheckListDeatails() {
      const url = `SearchChecklistName=&SortBy=&SortExp=&ModuleName=Project&PageNumber=1&PageSize=10&TaskId=${this.TaskId}`;
      DataService.GetChecklistDeatils(url).then(response => {
        if (response?.data?.result?.Data?.length) {
          this.CheckListdata = response.data.result.Data;
        } else {
          this.CheckListdata = [];
        }
        this.selectedIds = []; // reset selections
        this.selectAll = false;
      });
    },
    SaveChecklistdata() {
      const ids = this.selectedIds.join(',');
      const url = `TaskId=${this.TaskId}&CheckListids=${ids}`;
      DataService.AssociateChecklist(url).then(response => {
        if (response && response.data.status === 'Success') {
          this.ShowAlert(this.$t('AddedSuccess', [this.$t('Checklist')]), "success", true, this.$t("Alert"));
          this.$emit("callbackfunction");
          this.CloseTemplate();
        }
      });
    },
    SearchChecklistName() {
      const url = `SearchChecklistName=TC.checklist_name like '%${this.SearchName}%'&SortBy=&SortExp=&ModuleName=Project&PageNumber=1&PageSize=10`;
      DataService.GetChecklistDeatils(url).then(response => {
        this.CheckListdata = response?.data?.result?.Data || [];
        this.selectedIds = [];
        this.selectAll = false;
      });
    },
    RefreshSearchTemplate() {
      this.SearchName = '';
      this.CheckListDeatails();
    },
    CloseTemplate() {
      this.$parent.isAddCheckList = false;
    },
    AddCheckList() {
      this.IsAddCheckList = true;
    },
    CloseCheckList() {
      this.IsAddCheckList = false;
      this.CheckListDeatails();
    },
    EditCheckList(itm) {
      this.CheckListId = itm.checklist_id;
      this.IsAddCheckList = true;
    },
    commonDeleteData: function (id) {
      debugger
      var vm = this;
      var val = "";
      if (id != undefined) {
        val = id;
      } else {
        $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
          if (val.length > 0)
            val += ',';
          val += $(this).val();
        });
      }
      vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("CheckList")), function () {
        var postJSON = {
          ids: val,
          companyId: vm.companyId,
          userId: vm.userId,
          moduleName: "Project",
          refCode: "CHECKLIST"
        };
        var objectPostString = JSON.stringify(postJSON);
        DataService.CommonCommonDelete(objectPostString).then(response => {
          if (response.data[0].Status == "Success") {
            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('CheckList')]), "Success", true, vm.$t('Alert'));
            vm.CheckListDeatails();
          }
          else {
            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('CheckList')]), "failure", true, vm.$t('Alert'));
          }
        });
      });
    },
  }
};
</script>
