<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Preview') }} {{ $t(NewTabName) }} </h4>
                        <button type="button" class="close" v-on:click="HideCheckListPreview">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body" v-for="(item, index) in SectionData" :key="index">
                        <div class="heading-border mb-3">
                            <h5 class="h5"><span>{{ item.SectionTitle }}</span></h5>
                        </div>

                        <div class="row">
                            <div class="col-lg-12" v-for="(itm, idx) in item.ItemData" :key="idx">
                                <div class="form-group">
                                    {{ idx + 1 }}. {{ itm.title }}
                                    <div class="row">
                                        <!-- ✅ CheckBox -->

                                      
                                        <div class="ml-3" v-for="(tm, dx) in itm.options" :key="dx"
                                            v-if="itm.answer_type == 'CheckBox'">
                                            <div class="col-lg-12 col-sm-12">
                                                <label class="form-check form-check-inline">
                                                    <div class="custom-control custom-checkbox custom-control-inline">
                                                        <input :id="'checkbox-' + itm.id + '-' + dx" type="checkbox"
                                                                class="chkItems custom-control-input" :value="tm"
                                                                v-model="itm.selectedOptions"
                                                                @change="checkboxidds($event, itm, tm)" />
                                                        <label :for="'checkbox-' + itm.id + '-' + dx"
                                                            class="custom-control-label pt-1 pl-1">{{ tm }}</label>
                                                    </div>
                                                </label>
                                            </div>
                                        </div>

                                        <!-- ✅ Radio -->
                                        <div class="ml-3" v-for="(tm, dx) in itm.options" :key="dx"
                                            v-if="itm.answer_type == 'Radio'">
                                            <div class="col-lg-3">
                                                <div class="custom-control custom-radio custom-control-inline">
                                                    <input type="radio" class="custom-control-input dynamic"
                                                        :id="'radio-' + itm.id + '-' + dx" :name="'radio-' + itm.id"
                                                        :value="tm" v-model="itm.selectedRadio"
                                                        @change="checkboxidds($event, itm, tm)" />
                                                    <label class="custom-control-label"
                                                        :for="'radio-' + itm.id + '-' + dx">{{ tm }}</label>
                                                </div>
                                            </div>
                                        </div>

                                        <!-- ✅ TextBox -->
                                        <div class="col-lg-12" v-if="itm.answer_type == 'TextBox'">
                                            <input type="text" class="form-control" v-model="itm.textInput"
                                                @input="checkboxidds($event, itm, $event.target.value)" />
                                        </div>

                                        <!-- ✅ StarRating -->
                                        <div class="col-lg-12" v-if="itm.answer_type == 'StarRating'">
                                           
                                            <div class="col-lg-12">
                                                <a v-for="star in 5" :key="star" class="mr-2"
                                                    @click="checkboxidds($event, itm, star)"
                                                    :style="{ color: itm.starRating >= star ? '#FFD700' : '#d3d3d3' }">
                                                    <i class="fa fa-star"></i>
                                                </a>
                                            </div>
                                        </div>

                                        <!-- ✅ MarkAsDone -->
                                        <div class="col-lg-3" v-if="itm.answer_type == 'MarkAsDone'">
                                            <div class="col-lg-12 col-sm-12">
                                                <label class="form-check form-check-inline">
                                                    <div class="custom-control custom-checkbox custom-control-inline">
                                                        <input :id="'done-' + itm.id" type="checkbox"
                                                            class="chkItems custom-control-input" v-model="itm.markAsDone"
                                                            @change="checkboxidds($event, itm, $event.target.checked)" />
                                                        <label :for="'done-' + itm.id"
                                                            class="custom-control-label pt-1 pl-1">Mark As Done</label>
                                                    </div>
                                                </label>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="row flex-row-reverse mt-3 mb-3">
                        <div class="col-lg-6 text-right">
                            <a href="javascript:;" title="Save" class="btn btn-success mr-2" @click="SavePreviewData()">
                                <i class="fa fa-save pr-2"></i>{{ $t('Save') }} </a>
                            <a href="javascript:;" title="Cancel" class="btn btn-danger mr-2"
                                @click="HideCheckListPreview">
                                <i class="fa fa-close pr-2"></i>{{ $t('Close') }} </a>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService'
export default {
    props: {
        CheckListitemData: {
            type: Object
        },
        TaskId: {
            type: Number
        },
        NewTabName:{
            type:String,
            require: true
        }
    },
    data() {
        return {
            isLoading: false,
            SectionData: [],
            CheckListids: [
            ],
            rating: 0
        }
    },
    created: async function () {
        var vm = this;
        vm.PreviewData();
    },

    methods: {
        isChecked(itm, val) {
            return Array.isArray(itm.answer) && itm.answer.includes(val)
        },
        checkboxidds(evt, item, val) {
            debugger
            // Remove old entry for this item
            this.CheckListids = this.CheckListids.filter(obj => obj.Id !== item.id);
            let Obj = {};
            if (item.answer_type === "CheckBox") {
                if (!Array.isArray(item.selectedOptions)) item.selectedOptions = [];
                if (!Array.isArray(item.answer)) item.answer = [];

                if (evt.target.checked) {
                    item.selectedOptions.push(val);
                    item.answer.push(val);
                } else {
                    item.selectedOptions = item.selectedOptions.filter(a => a !== val);
                    item.answer = item.answer.filter(a => a !== val);
                }
                // Clear and repopulate CheckListids for this item
                this.CheckListids = this.CheckListids.filter(obj => obj.Id !== item.id);
                item.answer.forEach(ans => {
                    this.CheckListids.push({ Id: item.id, Answer: ans });
                });
            }
            else if (item.answer_type === "Radio") {
                item.answer = val;
                Obj = { Id: item.id, Answer: val };
                this.CheckListids.push(Obj);
            }
            else if (item.answer_type === "TextBox") {
                item.answer = val;
                Obj = { Id: item.id, Answer: val };
                this.CheckListids.push(Obj);
            }
            else if (item.answer_type === "StarRating") {
                item.answer = val;
                this.$set(item, 'starRating', val);
                Obj = { Id: item.id, Answer: val };
                this.CheckListids.push(Obj);
            }
            else if (item.answer_type === "MarkAsDone") {
                item.answer = val;
                if (val === true) {
                    Obj = { Id: item.id, Answer: "true" };
                    this.CheckListids.push(Obj);
                }
            }
        },
        PreviewData() {
           // debugger
            var vm = this;
            var url = `ChecklistId=${vm.CheckListitemData.checklist_id}&TaskId=${vm.TaskId}`
            DataService.PreviewData(url).then((response) => {
               // debugger
                if (response.data.result != null) {
                   // debugger
                    var Checklist = response.data.result.Checklist;
                    var ChecklistData = response.data.result.ChecklistData;
                    let Obj = {
                        SectionTitle: Checklist[0].checklist_name,
                        ItemData: ChecklistData
                    }
                    vm.SectionData.push(Obj);
                    vm.SectionData.forEach((item) => {
                        item.ItemData.forEach((ele) => {
                            if (ele.options != '' && ele.options != null) {
                                ele.options = ele.options.split(',');
                            }
                            if (ele.answer != '' && ele.answer != null) {
                                if (ele.answer_type === 'CheckBox') {
                                    ele.selectedOptions = ele.answer.split(',');
                                } else if (ele.answer_type === 'Radio') {
                                    ele.selectedRadio = ele.answer;
                                } else if (ele.answer_type === 'TextBox') {
                                    ele.textInput = ele.answer;
                                } else if (ele.answer_type === 'StarRating') {
                                    ele.starRating = parseInt(ele.answer);
                                } else if (ele.answer_type === 'MarkAsDone') {
                                    ele.markAsDone = ele.answer === 'true';
                                }
                                ele.answer = ele.answer.split(',');
                                ele.answer.forEach(item => {
                                    var Obj = {
                                        Id: ele.id,
                                        Answer: item,
                                    }
                                    vm.CheckListids.push(Obj);
                                })

                            }
                            if (ele.answer_type == 'StarRating') {
                                vm.rating = parseInt(ele.answer);
                            }

                        })
                    })

                     this.SectionData.forEach(section => {
                        section.ItemData = section.ItemData.filter(
                            (value, index, self) =>
                            index === self.findIndex(obj => obj.id === value.id)
                        );
                    });
                }
            })
        },
        HideCheckListPreview() {
            this.$parent.IsCheckListPreview = false;
        },
        SavePreviewData() {
            var vm = this;
            let resultJson = {
                TaskId: vm.TaskId,
                ChecklistId: vm.CheckListitemData.checklist_id,
                Item: vm.CheckListids
            };
            DataService.SaveChecklistItemData(JSON.stringify(resultJson)).then(function (response) {
                if (response.data.status == "Success") {
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('CheckList')]), "success", true, vm.$t("Alert"));
                    vm.$parent.IsCheckListPreview = false;
                    vm.$parent.CheckListData();
                }
                else {
                    vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                }
            });
        },
    }
}
</script>